 51→  relatedTaskCount: number;
 52→  relatedDecisionCount: number;
 53→};
 54→
 55→// ---------------------------------------------------------------------------
 56→// Pure comparison: claim vs reality for task completion
 57→// ---------------------------------------------------------------------------
 58→
 59→export function compareTaskCompletion(
 60→  signalsResult: GatherSignalsResult,
 61→): VerificationResult {
 62→  // No commits linked -> inconclusive
 63→  if (!signalsResult.hasCommits || signalsResult.signals.length === 0) {
 64→    return {
 65→      verdict: "inconclusive",
 66→      severity: "info",
 67→      verified: false,
 68→      text: "Unable to verify task completion: no external signals (commits or CI) found for this task.",
 69→    };
 70→  }
 71→
 72→  // Check CI status across all signals
 73→  const ciSignals = signalsResult.signals.filter(
 74→    (signal) => signal.ciStatus !== "unknown",
 75→  );
 76→
 77→  // All signals unknown -> inconclusive
 78→  if (ciSignals.length === 0) {
 79→    return {
 80→      verdict: "inconclusive",
 81→      severity: "info",
 82→      verified: false,
 83→      text: "Unable to verify task completion: CI status unavailable for linked commits.",
 84→      source: signalsResult.signals[0]?.source,
 85→    };
 86→  }
 87→
 88→  // Any failing CI -> mismatch
 89→  const failingSignals = ciSignals.filter(
 90→    (signal) => signal.ciStatus === "failure",
 91→  );
 92→
 93→  if (failingSignals.length > 0) {
 94→    const failingShas = failingSignals.map((s) => s.sha.slice(0, 8)).join(", ");
 95→    return {
 96→      verdict: "mismatch",
 97→      severity: "conflict",
 98→      verified: false,
 99→      text: `Task marked as completed but CI is failing for commit(s): ${failingShas}. Claim does not match reality.`,
100→      source: failingSignals[0]?.source,
101→    };
102→  }
103→
104→  // Any pending CI -> inconclusive (not verified yet)
105→  const pendingSignals = ciSignals.filter(
106→    (signal) => signal.ciStatus === "pending",
107→  );
108→
109→  if (pendingSignals.length > 0) {
110→    return {
111→      verdict: "inconclusive",
112→      severity: "info",
113→      verified: false,
114→      text: "Task completion verification pending: CI checks still running.",
115→      source: pendingSignals[0]?.source,
116→    };
117→  }
118→
119→  // All passing -> match
120→  const source = ciSignals[0]?.source;
121→  return {
122→    verdict: "match",
123→    severity: "info",
124→    verified: true,
125→    text: "Task completion verified: all linked CI checks are passing.",
126→    source,
127→  };
128→}
129→
130→// ---------------------------------------------------------------------------
131→// Pure comparison: intent completion verification
132→// ---------------------------------------------------------------------------
133→
134→export function compareIntentCompletion(
135→  signals: IntentSignals,
136→): VerificationResult {
137→  if (signals.status === "completed") {
138→    return {
139→      verdict: "match",
140→      severity: "info",
141→      verified: true,
142→      text: `Intent completed successfully: ${signals.goal}`,
143→      source: signals.hasTrace ? "trace" : undefined,
144→    };
145→  }
146→
147→  if (signals.status === "failed") {
148→    return {
149→      verdict: "mismatch",
150→      severity: "warning",
151→      verified: false,
152→      text: `Intent failed: ${signals.goal}`,
153→      source: signals.hasTrace ? "trace" : undefined,
154→    };
155→  }
156→
157→  return {
158→    verdict: "inconclusive",
159→    severity: "info",
160→    verified: false,
161→    text: `Intent in unexpected status '${signals.status}': ${signals.goal}`,
162→  };
163→}
164→
165→// ---------------------------------------------------------------------------
166→// Pure comparison: decision confirmation/supersession verification
167→// ---------------------------------------------------------------------------
168→
169→export function compareDecisionConfirmation(
170→  signals: DecisionSignals,
171→): VerificationResult {
172→  if (signals.status === "confirmed") {
173→    if (signals.completedTaskCount === 0) {
174→      return {
175→        verdict: "inconclusive",
176→        severity: "info",
177→        verified: false,
178→        text: `Decision confirmed: "${signals.summary}". No completed tasks in workspace.`,
179→      };
180→    }
181→
182→    return {
183→      verdict: "match",
184→      severity: "info",
185→      verified: true,
186→      text: `Decision confirmed: "${signals.summary}". ${signals.completedTaskCount} completed task(s) in workspace available for alignment review.`,
187→    };
188→  }
189→
190→  if (signals.status === "superseded") {
191→    if (signals.completedTaskCount === 0) {
192→      return {
193→        verdict: "inconclusive",
194→        severity: "info",
195→        verified: false,
196→        text: `Decision superseded: "${signals.summary}". No completed tasks found that may be affected.`,
197→      };
198→    }
199→
200→    return {
201→      verdict: "mismatch",
202→      severity: "warning",
203→      verified: false,
204→      text: `Decision superseded: "${signals.summary}". ${signals.completedTaskCount} completed task(s) in workspace may reference an outdated decision. Review for staleness.`,
205→    };
206→  }
207→
208→  return {
209→    verdict: "inconclusive",
210→    severity: "info",
211→    verified: false,
212→    text: `Decision in unexpected status '${signals.status}': "${signals.summary}"`,
213→  };
214→}
215→
216→// ---------------------------------------------------------------------------
217→// Pure comparison: observation peer review
218→// ---------------------------------------------------------------------------
219→
220→export function compareObservationPeerReview(
221→  signals: ObservationPeerReviewSignals,
222→): VerificationResult {
223→  const hasContext = signals.relatedTaskCount > 0 || signals.relatedDecisionCount > 0;
224→
225→  if (!hasContext) {
226→    return {
227→      verdict: "inconclusive",
228→      severity: "info",
229→      verified: false,
230→      text: `Peer review of ${signals.sourceAgent} observation: "${signals.originalText}". No related tasks or decisions found in workspace to cross-check this claim.`,
231→    };
232→  }
233→
234→  // When context exists, cross-check severity against workspace state
235→  if (signals.originalSeverity === "conflict") {
236→    return {
237→      verdict: "match",
238→      severity: "warning",
239→      verified: false,
240→      text: `Peer review of ${signals.sourceAgent} observation: "${signals.originalText}". Found ${signals.relatedTaskCount} task(s) and ${signals.relatedDecisionCount} decision(s) in workspace. Conflict claim requires human review.`,
241→    };
242→  }
243→
244→  if (signals.originalSeverity === "warning") {
245→    return {
246→      verdict: "match",
247→      severity: "info",
248→      verified: true,
249→      text: `Peer review of ${signals.sourceAgent} observation: "${signals.originalText}". Found ${signals.relatedTaskCount} task(s) and ${signals.relatedDecisionCount} decision(s) in workspace. Warning acknowledged and cross-checked.`,
250→    };
251→  }
252→
253→  return {
254→    verdict: "match",
255→    severity: "info",
256→    verified: true,
257→    text: `Peer review of ${signals.sourceAgent} observation: "${signals.originalText}". Cross-checked against ${signals.relatedTaskCount} task(s) and ${signals.relatedDecisionCount} decision(s).`,
258→  };
259→}
260→
261→export function compareCommitStatus(
262→  signalsResult: GatherSignalsResult,
263→): VerificationResult {
264→  // No CI signals available -> inconclusive
265→  if (signalsResult.signals.length === 0) {
266→    return {
267→      verdict: "inconclusive",
268→      severity: "info",
269→      verified: false,
270→      text: "Commit recorded: no CI status available for verification.",
271→    };
272→  }
273→
274→  const ciSignals = signalsResult.signals.filter(
275→    (signal) => signal.ciStatus !== "unknown",
276→  );
277→
278→  if (ciSignals.length === 0) {
279→    return {
280→      verdict: "inconclusive",
281→      severity: "info",
282→      verified: false,
283→      text: "Commit recorded: CI status unavailable.",
284→      source: signalsResult.signals[0]?.source,
285→    };
286→  }
287→
288→  const failingSignals = ciSignals.filter(
289→    (signal) => signal.ciStatus === "failure",
290→  );
291→
292→  if (failingSignals.length > 0) {
293→    return {
294→      verdict: "mismatch",
295→      severity: "warning",
296→      verified: false,
297→      text: `Commit has failing CI: ${failingSignals.map((s) => s.sha.slice(0, 8)).join(", ")}`,
298→      source: failingSignals[0]?.source,
299→    };
300→  }
301→
302→  const pendingSignals = ciSignals.filter(
303→    (signal) => signal.ciStatus === "pending",
304→  );
305→
306→  if (pendingSignals.length > 0) {
307→    return {
308→      verdict: "inconclusive",
309→      severity: "info",
310→      verified: false,
311→      text: "Commit verification pending: CI checks still running.",
312→      source: pendingSignals[0]?.source,
313→    };
314→  }
315→
316→  return {
317→    verdict: "match",
318→    severity: "info",
319→    verified: true,
320→    text: "Commit verified: all CI checks passing.",
321→    source: ciSignals[0]?.source,
322→  };
323→}
324→
325→// ---------------------------------------------------------------------------
326→// LLM verdict logic: skip optimization, confidence threshold, fallback
327→// ---------------------------------------------------------------------------
328→
329→/**
330→ * Determines whether the LLM should be invoked for verification.
331→ *
332→ * Skip conditions (all must be true):
333→ *   - workspace.settings.observer_skip_deterministic is true (or absent = default true)
334→ *   - deterministic verdict is "match"
335→ *   - CI is passing (source includes "github" or verified is true)
336→ */
337→export function shouldSkipLlm(
338→  deterministicVerdict: VerificationResult,
339→  skipDeterministic?: boolean,
340→): boolean {
341→  // Default to true when absent
342→  const skipEnabled = skipDeterministic ?? true;
343→
344→  if (!skipEnabled) return false;
345→
346→  return deterministicVerdict.verdict === "match" && deterministicVerdict.verified === true;
347→}
348→
349→/**
350→ * Applies confidence threshold and fallback to produce a final verification result.
351→ *
352→ * - LLM confidence < 0.5 → downgrade to inconclusive, severity=info
353→ * - LLM verdict=mismatch + confidence >= 0.5 → severity=conflict, type=contradiction
354→ * - LLM verdict=match + confidence >= 0.5 → severity=info, verified=true
355→ * - LLM failure (undefined) → fallback to deterministic with source=deterministic_fallback
356→ */
357→export function applyLlmVerdict(
358→  deterministicVerdict: VerificationResult,
359→  llmVerdict: LlmVerdict | undefined,
360→): VerificationResult {
361→  // Fallback: LLM failed or was not called
362→  if (!llmVerdict) {
363→    return {
364→      ...deterministicVerdict,
365→      source: "deterministic_fallback",
366→    };
367→  }
368→
369→  // Low confidence → downgrade to inconclusive
370→  if (llmVerdict.confidence < 0.5) {
371→    return {
372→      verdict: "inconclusive",
373→      severity: "info",
374→      verified: false,
375→      text: llmVerdict.reasoning,
376→      source: "llm",
377→      confidence: llmVerdict.confidence,
378→      evidenceRefs: llmVerdict.evidence_refs,
379→    };
380→  }
381→
382→  // Mismatch → contradiction
383→  if (llmVerdict.verdict === "mismatch") {
384→    return {
385→      verdict: "mismatch",
386→      severity: "conflict",
387→      verified: false,
388→      text: llmVerdict.reasoning,
389→      source: "llm",
390→      confidence: llmVerdict.confidence,
391→      evidenceRefs: llmVerdict.evidence_refs,
392→      observationType: "contradiction",
393→    };
394→  }
395→
396→  // Match → verified
397→  if (llmVerdict.verdict === "match") {
398→    return {
399→      verdict: "match",
400→      severity: "info",
401→      verified: true,
402→      text: llmVerdict.reasoning,
403→      source: "llm",
404→      confidence: llmVerdict.confidence,
405→      evidenceRefs: llmVerdict.evidence_refs,
406→      observationType: "validation",
407→    };
408→  }
409→
410→  // Inconclusive from LLM
411→  return {
412→    verdict: "inconclusive",
413→    severity: "info",
414→    verified: false,
415→    text: llmVerdict.reasoning,
416→    source: "llm",
417→    confidence: llmVerdict.confidence,
418→    evidenceRefs: llmVerdict.evidence_refs,
419→  };
420→}
