  1→/**
  2→ * Milestone 2: Verification Pipeline
  3→ *
  4→ * Traces: Story 1 (Task Verification), Story 2 (Intent Verification),
  5→ *         Story 2b (Commit Verification), Story 3 (Graceful Degradation)
  6→ *
  7→ * Validates the core claim-vs-reality comparison:
  8→ * - match -> observation severity: info, verified: true
  9→ * - mismatch -> observation severity: conflict, verified: false
 10→ * - inconclusive -> observation severity: info, note missing source
 11→ * - External API failures do NOT block the original workflow
 12→ *
 13→ * Driving ports:
 14→ *   POST /api/observe/task/:id
 15→ *   POST /api/observe/intent/:id
 16→ *   POST /api/observe/git_commit/:id
 17→ */
 18→import { describe, expect, it, beforeAll, afterAll } from "bun:test";
 19→import { RecordId } from "surrealdb";
 20→import {
 21→  setupObserverSuite,
 22→  wireObserverEvents,
 23→  setupObserverWorkspace,
 24→  createTaskWithCommit,
 25→  createCompletedIntent,
 26→  createGitCommit,
 27→  triggerTaskCompletion,
 28→  triggerIntentCompletion,
 29→  waitForObservation,
 30→  getWorkspaceObservations,
 31→  createMockGitHubServer,
 32→} from "./observer-test-kit";
 33→
 34→const getRuntime = setupObserverSuite("observer_m2_verification");
 35→
 36→let mockGitHub: ReturnType<typeof createMockGitHubServer>;
 37→let originalGitHubUrl: string | undefined;
 38→
 39→beforeAll(async () => {
 40→  const { surreal, port } = getRuntime();
 41→  await wireObserverEvents(surreal, port);
 42→
 43→  // Single file-level mock GitHub server — tests add routes dynamically.
 44→  // Prevents race conditions when SurrealDB ASYNC+RETRY events outlive per-test mocks.
 45→  mockGitHub = createMockGitHubServer();
 46→  originalGitHubUrl = process.env.GITHUB_API_URL;
 47→  process.env.GITHUB_API_URL = mockGitHub.url;
 48→});
 49→
 50→afterAll(() => {
 51→  mockGitHub?.stop();
 52→  if (originalGitHubUrl !== undefined) {
 53→    process.env.GITHUB_API_URL = originalGitHubUrl;
 54→  } else {
 55→    delete process.env.GITHUB_API_URL;
 56→  }
 57→});
